import{_ as o,o as d,c as t,a2 as c}from"./chunks/framework.DvFsUg-r.js";const u=JSON.parse('{"title":"Oracle Autonomous DB 연결 — .env 한 줄부터 6겹의 오류까지","description":"","frontmatter":{"slug":"oracle-adb-connection","title":"Oracle Autonomous DB 연결 — .env 한 줄부터 6겹의 오류까지","authors":[],"tags":["oracle","autonomous-database","wallet","dotenv","spring-boot","liquibase","troubleshooting"],"created":"2026-05-31 09:28 (KST)","date":"2026-05-31T00:28:00.000Z"},"headers":[],"relativePath":"journal/2026-05-31-oracle-adb-connection.md","filePath":"journal/2026-05-31-oracle-adb-connection.md","lastUpdated":1781092690000}'),a={name:"journal/2026-05-31-oracle-adb-connection.md"};function n(s,e,r,l,i,p){return d(),t("div",null,[...e[0]||(e[0]=[c('<p>에이전트 앱을 로컬에서 <strong>Oracle Cloud Autonomous Database(ATP)</strong> 에 붙이는 작업. 설정은 <code>.env</code> 한 줄 추가로 끝날 줄 알았지만, 기동할 때마다 오류가 <strong>한 겹씩</strong> 바뀌며 드러났다. 각 오류가 정확히 어느 계층에서 막혔는지 — 그리고 &quot;네트워크를 열어야 하나?&quot;라는 질문의 진짜 답 — 을 순서대로 정리한 개발 로그다.</p><h2 id="출발점-dotenv-java-로-env-주입" tabindex="-1">출발점: dotenv-java 로 .env 주입 <a class="header-anchor" href="#출발점-dotenv-java-로-env-주입" aria-label="Permalink to &quot;출발점: dotenv-java 로 .env 주입&quot;">​</a></h2><p>접속 정보(URL·계정·비밀번호)를 코드 밖으로 빼려고 <code>dotenv-java</code> 를 넣었다. 다만 의존성만 추가해서는 Spring 의 <code>${...}</code> 플레이스홀더에 값이 들어가지 않는다. 그래서 <code>main()</code> 에서 <code>.env</code> 를 읽어 <strong>시스템 프로퍼티로 올린 뒤</strong> <code>SpringApplication.run</code> 을 호출하도록 했다. <code>application.yml</code> 의 <code>${ORACLE_URL}</code> 등이 이 값을 해석한다.</p><p>여기까지는 평범했다. 진짜 이야기는 기동 버튼을 누른 다음부터다.</p><h2 id="_6겹의-오류를-한-겹씩" tabindex="-1">6겹의 오류를 한 겹씩 <a class="header-anchor" href="#_6겹의-오류를-한-겹씩" aria-label="Permalink to &quot;6겹의 오류를 한 겹씩&quot;">​</a></h2><p>기동 → 오류 → 원인 추적 → 수정 → 재기동. 매번 오류 메시지가 <em>바뀌었다</em>는 건 앞 계층을 제대로 통과했다는 신호였다.</p><table tabindex="0"><thead><tr><th>#</th><th>오류</th><th>무엇이 막혔나</th><th>원인</th><th>해결</th></tr></thead><tbody><tr><td>1</td><td>비밀번호가 잘려 들어감</td><td><code>.env</code> 파싱</td><td>dotenv 가 따옴표 없는 값의 <code>#</code> 이후를 <strong>인라인 주석</strong>으로 절단 (<code>ahfdlq...#@</code> → <code>ahfdlq...</code>)</td><td>값을 큰따옴표로 감쌈</td></tr><tr><td>2</td><td><code>ORA-12541</code> (localhost:1521 리스너 없음)</td><td><code>.env</code> 로딩</td><td>IntelliJ 실행 시 작업 디렉터리가 <code>app/</code> 가 아니라 <code>.env</code> 미발견 → <code>application.yml</code> 기본값(localhost)으로 폴백</td><td><code>.env</code> 탐색을 CWD 무관하게(상위로 올라가며 <code>.env</code>·<code>app/.env</code> 탐색)</td></tr><tr><td>3</td><td><code>ORA-17957</code> / <code>SSO not found</code></td><td>지갑 파일</td><td><code>TNS_ADMIN</code> 경로에 wallet 파일 자체가 없음</td><td>OCI 지갑 zip 을 해당 경로에 압축 해제</td></tr><tr><td>4</td><td><code>ORA-17957</code> / <code>SSO KeyStore not available</code></td><td>지갑 <strong>읽기</strong></td><td>SSO 자동로그인 지갑(<code>cwallet.sso</code>)을 thin 드라이버가 읽을 <code>oraclepki</code> 부재</td><td><code>com.oracle.database.security:oraclepki</code> 의존성 추가</td></tr><tr><td>5</td><td><code>ORA-01017</code> (invalid username/password)</td><td><strong>인증</strong></td><td>비밀번호 불일치</td><td>OCI 콘솔에서 ADMIN 비밀번호 재설정</td></tr><tr><td>6</td><td><code>ORA-12838</code> (병렬 수정 후 객체 접근 불가)</td><td><strong>DML 실행</strong></td><td><code>_high</code> 컨슈머 그룹이 Liquibase INSERT 를 병렬/직접경로로 실행</td><td>서비스를 <code>_tp</code> 로 변경</td></tr></tbody></table><h2 id="네트워크를-열어야-하나" tabindex="-1">&quot;네트워크를 열어야 하나?&quot; <a class="header-anchor" href="#네트워크를-열어야-하나" aria-label="Permalink to &quot;&quot;네트워크를 열어야 하나?&quot;&quot;">​</a></h2><p>중간에 가장 헷갈렸던 지점. 결론부터 말하면 <strong>아니오</strong> 였다.</p><p>오류가 5번(<code>ORA-01017</code>, 인증 거부)에 도달했다는 것 자체가 <strong>TLS 핸드셰이크가 성공해 DB 리스너까지 도달했다</strong>는 증거다. 방화벽이나 ACL 로 막혀 있었다면 인증 오류가 아니라 <code>IO Error</code> / <code>ORA-12170</code> 같은 <strong>타임아웃</strong>이 났을 것이다. 즉 <code>SSO not found</code> 와 <code>connection timeout</code> 은 전혀 다른 계층의 문제이고, 전자는 네트워크와 무관한 <strong>로컬 키스토어 초기화</strong> 단계의 실패였다.</p><p>오류 메시지의 <em>종류</em>가 어느 계층까지 갔는지를 알려준다 — 이게 이번 디버깅의 핵심 교훈이다.</p><h2 id="high-vs-tp" tabindex="-1"><code>_high</code> vs <code>_tp</code> <a class="header-anchor" href="#high-vs-tp" aria-label="Permalink to &quot;`_high` vs `_tp`&quot;">​</a></h2><p>마지막 <code>ORA-12838</code> 은 서비스 선택 문제였다. 이 인스턴스는 <code>_high</code>/<code>_medium</code>/<code>_low</code> 와 함께 <code>_tp</code>/<code>_tpurgent</code> 를 제공하는 <strong>ATP(트랜잭션 처리)</strong> 다.</p><ul><li><code>_high</code>·<code>_medium</code>·<code>_low</code> — 분석용 고병렬 컨슈머 그룹. <code>_high</code> 는 DML 도 병렬/ 직접경로로 돌려, Liquibase 가 <code>DATABASECHANGELOGLOCK</code> 에 INSERT 후 같은 트랜잭션에서 다시 접근하자 <code>ORA-12838</code> 이 터졌다.</li><li><code>_tp</code> — 트랜잭션 처리용. DML 을 직렬로 실행하므로 <code>ORA-12838</code> 이 없고, OLTP 성격의 이 앱(로그인·RBAC·감사)에 <strong>애초에 맞는 선택</strong>이다.</li></ul><p>서비스명을 <code>..._high</code> → <code>..._tp</code> 로 바꾸자 깔끔히 통과했다.</p><h2 id="결과" tabindex="-1">결과 <a class="header-anchor" href="#결과" aria-label="Permalink to &quot;결과&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ChangeSet 004-* ... ran successfully   (스키마 26 + 시드 7 = 33개)</span></span>\n<span class="line"><span>Liquibase: Update has been successful. Rows affected: 19</span></span>\n<span class="line"><span>Tomcat started on port 8080 (http)</span></span>\n<span class="line"><span>Started AgentApplication in 10.8 seconds</span></span></code></pre></div><p>Liquibase 가 <code>SYS_*</code>·<code>AUDIT_*</code> 테이블과 기본 시드를 ATP 에 생성하고, 앱이 8080 에 정상 기동했다.</p><h2 id="남긴-것-교훈" tabindex="-1">남긴 것 / 교훈 <a class="header-anchor" href="#남긴-것-교훈" aria-label="Permalink to &quot;남긴 것 / 교훈&quot;">​</a></h2><ul><li><strong><code>.env</code> 값에 <code>#</code> 가 있으면 따옴표</strong> — dotenv 의 인라인 주석에 잘린다. <code>$</code> 도 변수 치환 위험이 있어 주의.</li><li><strong><code>.env</code> 로딩은 실행 방식(IntelliJ/gradle/jar)에 따라 CWD 가 달라진다</strong> — 작업 디렉터리에 의존하지 말고 파일을 탐색하게 만들 것. 기동 로그에 <code>[dotenv] loaded ...</code> 를 남겨 어떤 파일을 읽었는지 바로 보이게 했다.</li><li><strong>SSO 지갑(<code>cwallet.sso</code>)에는 <code>oraclepki</code> 가 필수</strong> — 없으면 네트워크와 무관하게 <code>SSO not found</code> 로 죽는다.</li><li><strong>앱 워크로드엔 <code>_tp</code></strong> — <code>_high</code> 는 분석/배치용. <code>ORA-12838</code> 은 서비스 선택 신호.</li></ul><p>접속 정보(<code>ORACLE_URL</code>·계정·비밀번호)는 <code>app/.env</code> 에 두고 커밋하지 않는다. 공유용 템플릿은 <code>app/.env.example</code> 참고.</p>',21)])])}const g=o(a,[["render",n]]);export{u as __pageData,g as default};
